 My convert function:
(Service is development by C++11 with Mongo C Driver.)
---------------------

bson_t* MongoDBClient::Json2Bson(const std::string& json)
{
	const size_t buffsize = 512;
	bson_json_reader_t *reader = bson_json_data_reader_new(1, buffsize);
	if (reader == NULL)
		return NULL;

	bson_json_data_reader_ingest(reader, (const uint8_t *)json.data(), json.length());

	bson_error_t error;
	bson_t* doc = bson_new();
	bson_t* doc2 = bson_new();

	int state = bson_json_reader_read (reader, doc, &error);
	if (state < 0)
	{
		bson_destroy (doc);
		bson_destroy (doc2);
		bson_json_reader_destroy (reader);
		LOG_ERROR("convert json %s to bson failed. error: %s", json.c_str(), error.message);
		return NULL;
	}

	state = bson_json_reader_read (reader, doc2, &error);
	if (state != 0)
	{
		bson_destroy (doc);
		bson_destroy (doc2);
		bson_json_reader_destroy (reader);
		LOG_ERROR("convert json %s to bson failed. Json not a single object, reentered.", json.c_str());
		return NULL;
	}

	bson_destroy (doc2);
	bson_json_reader_destroy (reader);
	
	return doc;
}

When I implemented find and getMore commands for MongoDB 3.2+ in CDRIVER-838, I wrote the getMore command to send the cursor's batchSize as the getMore command's "batchSize" parameter unconditionally.

The correct behavior is to send a batchSize of:
{code}
MIN (batchSize, limit - numberReceived)
{code}
